declare @message nvarchar(4000)
select @message = ''

        &CommandControlLocationLotShowing;

select @message as message
return






        select 'this._voucherCode='@@id';load$GridVoucherDetail$(this);' as message
return




        select 'dispose$GridVoucherDetail$(this);' as message
return







/* <flatten type="Javascript"> */
function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_onResponseComplete(on$GridVoucherDetail$ResponseComplete);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {
    gia_nt0_sl: '[gia_nt0]:=([gia_nt0] == 0 ? ([so_luong] != 0 ? ([tien_nt0]/[so_luong]) : 0) : [gia_nt0])',
    gia0_sl: '[gia0]:=([gia0] == 0 ? ([so_luong] != 0 ? ([tien0]/[so_luong]) : 0) : [gia0])',

    gia0_tg: '[gia0]:=[gia_nt0]*[$ty_gia]',
    tien_nt0: '[tien_nt0]:=[so_luong]*[gia_nt0]',
    tien0: '[tien0]:=[so_luong]*[gia0]',
    tien0_tg: '[tien0]:=[tien_nt0]*[$ty_gia]',

    t_so_luong: ['t_so_luong', 'so_luong'],
    t_tien_nt0: ['t_tien_nt0', 'tien_nt0'],
    t_tien0: ['t_tien0', 'tien0'],

    t_tt_nt: '[t_tt_nt]:=[t_tien_nt0]+[t_cp_nt]+[t_thue_nt]',
    t_tt: '[t_tt]:=[t_tien0]+[t_cp]+[t_thue]'
  };
  g.$h = [['voucherCode', 'String', g._voucherCode], 'ma_dvcs'];
  udf$Detail$(g);
}
function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridVoucherDetail$ResponseComplete);} catch (ex) {}
}
function onChange$GridVoucherDetail$Item(o) {o.grid.request(o, 'Item', 'Item', ['ma_vt', 'ma_kho'], o.grid.$h, true);}
function onChange$GridVoucherDetail$UOM(o) {o.grid.request(o, 'UOM', 'UOM', ['ma_vt', 'ma_kho', 'dvt', 'so_luong'], o.grid.$h, true);}
function onChange$GridVoucherDetail$Site(o) {o.grid.request(o, 'Site', 'Site', ['ma_vt','ma_kho'], o.grid.$h, true);}
function onChange$GridVoucherDetail$CreditAccount(o) {o.grid.request(o, 'Reason', 'Reason', ['ma_nx'], o.grid.$h, true);}
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'so_luong':
      g.validExpression(o, [g.$a.tien_nt0, g.$a.tien0], [g.$a.t_so_luong, g.$a.t_tien_nt0, g.$a.t_tien0], [g.$a.t_tt_nt, g.$a.t_tt], 'gia_nt0');
      break;
    case 'gia_nt0':
      g.validExpression(o, [g.$a.gia0_tg, g.$a.tien_nt0, g.$a.tien0], [g.$a.t_tien_nt0, g.$a.t_tien0], [g.$a.t_tt_nt, g.$a.t_tt], 'tien_nt0');
      break;
    case 'tien_nt0':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_nt0_sl, g.$a.gia0_tg]);
      g.validExpression(o, [g.$a.tien0_tg], [g.$a.t_tien_nt0, g.$a.t_tien0], [g.$a.t_tt_nt, g.$a.t_tt]);
      break;
    case 'gia0':
      g.validExpression(o, [g.$a.tien0], [g.$a.t_tien0], [g.$a.t_tt], 'tien0');
      break;
    case 'tien0':
      if (f._calPrice) g.validExpression(o, [g.$a.gia0_sl]);
      g.validExpression(o, null, [g.$a.t_tien0], [g.$a.t_tt]);
      break;
    default:
      break;
  }
}
/* </flatten> */
function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {&ScriptCheckGridAction;
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'Check':
      if (!(g.validRowExpression('px_gia_dd', '([gia_ton] != 3) || ([gia_ton] == 3 && ![px_gia_dd])'))) break;
      if (!(g.validRowExpression('so_luong', '([gia_ton] != 3) || ([gia_ton] == 3 && [so_luong] != 0)'))) break;
      if (g._tracked$Lot && !(g.validRowExpression('ma_lo', '(![lo_yn]) || ([ma_lo] != "")'))) break;
      if (g._tracked$Location) g.validRowExpression('ma_vi_tri', '(![vi_tri_yn]) || ([ma_vi_tri] != "")');
      break;
    case 'Retrieve':
      if (f._action == 'View') break;
      if (!f.validFields('ma_kh, ngay_lct')) break;
      switch (e.type.Value) {
        case '10':
          g.showForm('PGOrderFilter');
          break;
        case '30':
          if (f.getItemValue('loai_ct') == '1' || f.getItemValue('loai_ct') == '3' ) g.showForm('PGReceiptFilter');
          break;
        default:
          break;
      }
      break;
    case 'Copying':
      set$Voucher$EmptyExternalField(g, 'dh_so, dh_ln, pn_so, pn_ln, stt_rec_dh, stt_rec0dh, stt_rec_pn, stt_rec0pn');
      break;
&AutoLotGrid;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function on$GridVoucherDetail$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
    case 'Item':
      var v = (result[0].Value == '' ? true : null), t = (result[0].Value == '' ? 'false' : 'true');
      g.setItemGridBehavior(o, [
        ['ma_lo', '', null, null],
        ['ma_kho', result[0].Value, '', true],
        ['ma_vi_tri', result[1].Value, '', v],
        ['dvt', result[2].Value, '', true],
        ['he_so', result[3].Value, null, null],
        ['tk_vt', result[4].Value, '', true],
        ['gia_ton', result[5].Value, null, null],
        ['vi_tri_yn', [result[6].Value, t], null, null],
        ['lo_yn', result[7].Value, null, null],
        ['tao_lo', result[10].Value, null, null]
      ]);
      g.live(o, 'dvt');
      break;
    case 'UOM':
      g.setItemGridBehavior(o, [['he_so', result[0].Value, '', true]]);
      break;
    case 'Site':
      g.setItemGridBehavior(o, [['tk_vt', result[0].Value, '', true], ['ma_vi_tri', '', '', null], ['vi_tri_yn', result[1].Value, null, null]]);
      break;
    case 'Reason':
      g.setItemGridBehavior(o, [['tk_cpxt', result[0].Value, '', true]]);
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$RowChange(g, f) {
  g.executeAggregate([g.$a.t_so_luong, g.$a.t_tien_nt0, g.$a.t_tien0]);
  f.executeExpression([g.$a.t_tt_nt, g.$a.t_tt]);
}
/* </flatten> */

